import{o as a,c as m,D as e}from"./framework.2deede19.js";const t='{"title":"Вступление","description":"","frontmatter":{"title":"Вступление","subtitle":"Шива сутра вимаршини. Глава 1.","tags":"vim-1","date":"2021-03-02T00:00:00.000Z"},"headers":[{"level":2,"title":"Умиротворяющая молитва к Шанкаре (Śaṅkara)","slug":"умиротворяющая-моnитва-к-шанкаре-sankara"},{"level":2,"title":"Причины написания этого комментария","slug":"причины-написания-этого-комментария"},{"level":2,"title":"Открытие Шивасутр","slug":"открытие-шивасутр"}],"relativePath":"texts/shiva-sutra-vimarshini/1/start.md","lastUpdated":1625522466864}',r={},i=e('<div class="stanza"><h2 id="умиротворяющая-моnитва-к-шанкаре-sankara"><a class="header-anchor" href="#умиротворяющая-моnитва-к-шанкаре-sankara" aria-hidden="true">#</a> Умиротворяющая молитва к Шанкаре (Śaṅkara)</h2><p class="sans">रुद्रक्षेत्रज्ञवर्गः समुदयति यतो यत्र विश्रान्तिमृच्छेद्-<br> यत्तत्त्वं यस्य विश्वं स्फुरितमयमियद्यन्मयं विश्वमेतत्।<br> स्वाच्छन्द्यानन्दवृन्दोच्छलदमृतमयानुत्तरस्पन्दतत्त्वं<br> चैतन्यं शाङ्करं तज्जयति यदखिलं द्वैतभासाद्वयात्म॥</p><p class="trans">Rudrakṣetrajñavargaḥ samudayati yato yatra viśrāntimṛcched-<br> yattattvaṁ yasya viśvaṁ sphuritamayamiyadyanmayaṁ viśvametat|<br> Svācchandyānandavṛndocchaladamṛtamayānuttaraspandatattvaṁ<br> caitanyaṁ śāṅkaraṁ tajjayati yadakhilaṁ dvaitabhāsādvayātma||</p><p>Это <em>(tad)</em> Сознание <em>(caitanyam)</em> Шанкары <em>(śāṅkaram)</em> торжествует победу --т.е. оно &quot;победоносное&quot;-- <em>(jayati)</em>, которое <em>(yad)</em> [является] полностью <em>(akhilam)</em> недвойственным <em>(advaya-ātma)</em>, [но имеет] внешний вид, или сияние <em>(bhāsa)</em> дуальности <em>(dvaita)</em>, которое <em>(yad)</em> [есть] Реальность <em>(tattvam)</em>, из которого <em>(yatas)</em> вид, или группа <em>(vargaḥ)</em> Rudra-s <em>(rudra)</em> [и] Kṣetrajña-s <em>(kṣetrajña)</em> возникает <em>(samudayati)</em>, [и] в котором <em>(yatra)</em> приходит к покою <em>(viśrāntim ṛcchet)</em>, чья <em>(yasya)</em> вселенная <em>(viśvam)</em> состоит <em>(mayam)</em> из пульсаций <em>(sphurita)</em> --или также, альтернативный перевод мог бы быть &quot;чья вселенная вспыхивает в поле зрения оттуда&quot;--, чья <em>(yasya)</em> протяженность <em>(iyat)</em> [есть] эта [самая] <em>(etad)</em> вселенная <em>(viśvam)</em>, которая полна <em>(mayam)</em> Этого --т.е. этого вышеупомянутого Сознания-- <em>(yad)</em>. [Короче говоря, это Сознание Шанкары является] Принципом <em>(tattvam)</em> Изначальной Вибрации <em>(spanda)</em> Ануттара (Anuttara) --т.е. &quot;Шивы, Высшего Существа&quot;-- <em>(anuttara)</em>, состоящим <em>(maya)</em> из Нектара <em>(amṛta)</em>, исходящего <em>(ucchalat)</em> из Массы <em>(vṛnda)</em> Свободы <em>(svācchandya)</em> и Блаженства <em>(ānanda)</em>.</p></div><div class="stanza"><h2 id="причины-написания-этого-комментария"><a class="header-anchor" href="#причины-написания-этого-комментария" aria-hidden="true">#</a> Причины написания этого комментария</h2><p class="sans">असामञ्जस्यमालोच्य वृत्तीनामिह तत्त्वतः।<br> शिवसूत्रं व्याकरोमि गुर्वाम्नायविगानतः॥</p><p class="trans">Asāmañjasyamālocya vṛttīnāmiha tattvataḥ|<br> Śivasūtraṁ vyākaromi gurvāmnāyavigānataḥ||</p><p>Отметив <em>(ālocya)</em> несоответствие <em>(asāmañjasyam)</em> в комментариях <em>(vṛttīnām)</em> в это время <em>(iha)</em>, поскольку они не согласуются <em>(vigānataḥ)</em> со Священной Традицией <em>(āmnāya)</em> Гуру, или Мастеров <em>(guru)</em>, Я излагаю <em>(vyākaromi)</em> Śivasūtra-s <em>(śivasūtram)</em> в соответствии с их реальным значением <em>(tattvatas)</em>.</p></div><div class="stanza"><h2 id="открытие-шивасутр"><a class="header-anchor" href="#открытие-шивасутр" aria-hidden="true">#</a> Открытие Шивасутр</h2><p class="sans">इह कश्चिच्छक्तिपातवशोन्मिषन्माहेश्वरभक्त्यतिशयादनङ्गीकृताधरदर्शनस्थनागबोध्यादिसिद्धादेशनः शिवाराधनपरः पारमेश्वरनानायोगिनीसिद्धसत्सम्प्रदायपवित्रितहृदयः श्रीमहादेवगिरौ महामाहेश्वरः श्रीमान् वसुगुप्तनामा गुरुरभवत्।<br> कदाचिच्चासौ द्वैतदर्शनाधिवासितप्राये जीवलोके रहस्यसम्प्रदायो मा विच्चेदीत्याशयतोऽनुजिघृक्षापरेण परमशिवेन स्वप्नेऽनुग्रह्योन्मिषितप्रतिभः कृतो यथात्र महीभृति महति शिलातले रहस्यमस्ति तदधिगम्यानुग्रहयोग्येषु प्रकाशयेति। प्रबुद्धश्चासावन्विष्यंस्तां महतीं शिलां करस्पर्शनमात्रपरिवर्तनतः संवादीकृतस्वप्नां प्रत्यक्षीकृत्येमानि शिवोपनिषत्सङ्ग्रहरूपाणि शिवसूत्राणि ततः समाससाद। एतानि च सम्यगधिगम्य भट्टश्रीकल्लटाद्येषु सच्छिष्येषु प्रकाशितवान् स्पन्दकारिकाभिश्च सङ्गृहीतवान्। तत्पारम्पर्यप्राप्तानि स्पन्दसूत्राण्यस्माभिः स्पन्दनिर्णये सम्यग्निर्णीतानि। शिवसूत्राणि तु निर्णीयन्ते॥<br> तत्र प्रथमं नरेश्वरभेदवादिप्रातिपक्ष्येण चैतन्यपरमार्थतः शिव एव विश्वस्यात्मेत्यादिशति—</p><p class="trans">Iha kaścicchaktipātavaśonmiṣanmāheśvarabhaktyatiśayādanaṅgīkṛtādharadarśanasthanāgabodhyādisiddhādeśanaḥ śivārādhanaparaḥ pārameśvaranānāyoginīsiddhasatsampradāyapavitritahṛdayaḥ śrīmahādevagirau mahāmāheśvaraḥ śrīmān vasuguptanāmā gururabhavat|<br> Kadāciccāsau dvaitadarśanādhivāsitaprāye jīvaloke rahasyasampradāyo mā vicchedītyāśayato&#39;nujighṛkṣāpareṇa paramaśivena svapne&#39;nugrahyonmiṣitapratibhaḥ kṛto yathātra mahībhṛti mahati śilātale rahasyamasti tadadhigamyānugrahayogyeṣu prakāśayeti|<br> Prabuddhaścāsāvanviṣyaṁstāṁmahatīṁ śilāṁ karasparśanamātraparivartanataḥ saṁvādīkṛtasvapnāṁ pratyakṣīkṛtyemāni śivopaniṣatsaṅgraharūpāṇi śivasūtrāṇi tataḥ samāsasāda|<br> Etāni ca samyagadhigamya bhaṭṭaśrīkallaṭādyeṣu sacchiṣyeṣu prakāśitavān spandakārikābhiśca saṅgṛhītavān|<br> Tatpāramparyaprāptāni spandasūtrāṇyasmābhiḥ spandanirṇaye samyagnirṇītāni|<br> Śivasūtrāṇi tu nirṇīyante||<br> Tatra prathamaṁ nareśvarabhedavādiprātipaksyeṇa caitanyaparamārthataḥ śiva eva viśvasyātmetyādiśati—</p><p>В этом мире <em>(iha)</em>, на священной <em>(śrī)</em> горе <em>(girau)</em> Mahādeva <em>(mahādeva)</em>, некто <em>(kaścid)</em>, достойный почтения <em>(śrīmān)</em> ,[жил]. Его сердце <em>(hṛdayaḥ)</em> было очищено <em>(pavitrita)</em> Благородной <em>(sat)</em> Традицией <em>(sampradāya)</em> различных <em>(nānā)</em> Совершенных Существ <em>(siddha)</em> и Йогинь <em>(yoginī)</em>, принадлежащей Великому Господу <em>(pārameśvara)</em>. Он был посвящен <em>(paraḥ)</em> поклонению <em>(ārādhana)</em> Возвышенному <em>(śiva)</em>. Благодаря избытку <em>(atiśayāt)</em> преданности <em>(bhakti)</em> Великому Господу <em>(māheśvara)</em>, которая [преданность] сияла [в нем] <em>(unmiṣat)</em>, благодаря <em>(vaśa)</em> Нисхождению <em>(pāta)</em> Силы <em>(śakti)</em> --т.е. Божественной Милости--, (он) давал учение <em>(ādeśanaḥ)</em>, которое не соответствовало мнению <em>(anaṅgīkṛta)</em> таких Совершенных Существ [в Буддизме] <em>(siddha)</em>, как Нагабодхи <em>(nāgabodhi)</em> и других <em>(ādi)</em>, имевших <em>(stha)</em> более низкую <em>(adhara)</em> точку зрения <em>(darśana)</em>. Он был <em>(abhavat)</em> великим преданным Господа <em>(mahāmāheśvaraḥ)</em> и Гуру <em>(guruḥ)</em>. Его имя <em>(nāmā)</em> - Васугупта <em>(vasugupta)</em>.</p><p>И <em>(ca)</em> однажды <em>(kadācid)</em>, Великий <em>(parama)</em> Шива <em>(śivena)</em>, вознамерившись <em>(pareṇa)</em> проявить Благоволение <em>(anujighṛkṣā)</em> с целью <em>(iti-āśayataḥ)</em>, чтобы: &quot;Пусть Тайная <em>(rahasya)</em> Традиция <em>(sampradāyaḥ)</em> не <em>(mā)</em> прерывается <em>(vicchedi)</em> в этом мире <em>(loke)</em> живых существ <em>(jīva)</em>, которые в основном <em>(prāye)</em> благоухают <em>(adhivāsita)</em> дуалистической <em>(dvaita)</em> точкой зрения <em>(darśana)</em>!&quot;; расширил <em>(unmiṣita... kṛtaḥ)</em> во сне <em>(svapne)</em> сознание <em>(pratibhaḥ)</em> этого [Васугупты] <em>(asau)</em>, даровав ему Божественную Милость <em>(anugrahya)</em>. [Он сказал ему] так <em>(yathā... iti)</em>:</p><blockquote><p>&quot;Здесь <em>(atra)</em>, на этой горе <em>(mahībhṛti)</em>, находится <em>(asti)</em> Секретное Эзотерическое Учение <em>(rahasyam)</em> под <em>(tale)</em> большим <em>(mahati)</em> камнем <em>(śilā)</em>. Получив его <em>(tad adhigamya)</em>, раскрой его <em>(prakāśaya)</em> тем, кто подходит <em>(yogyeṣu)</em> для получения Божественной Милости <em>(anugraha)</em>&quot;.</p></blockquote><p>Проснувшись <em>(prabuddhaḥ ca)</em>, он --т.е. Васугупта-- <em>(asau)</em> начал искать <em>(anviṣyan)</em> этот <em>(tām)</em> большой <em>(mahatīm)</em> камень <em>(śilām)</em>. [И найдя,] он повернул его <em>(parivartanataḥ)</em> всего лишь <em>(mātra)</em> прикосновением <em>(sparśana)</em> руки <em>(kara)</em> и увидел своими собственными глазами <em>(pratyakṣīkṛtya)</em>, (что) сон <em>(svapnām)</em> подтвердился <em>(saṁvādīkṛta)</em>. Таким образом, он <em>(tatas)</em> получил <em>(samāsasāda)</em> эти <em>(imāni)</em> Афоризмы <em>(sūtrāṇi)</em> Шивы <em>(śiva)</em>, которые <em>(rūpāṇi)</em> являются кратким изложением <em>(saṅgraha)</em> Тайного Учения <em>(upaniṣad)</em> Шивы <em>(śiva)</em>.</p><p>И <em>(ca)</em>, полностью <em>(samyak)</em> изучив их <em>(etāni... adhigamya)</em>, он раскрыл их <em>(etāni... prakāśitavān)</em> таким выдающимся <em>(sad)</em> ученикам <em>(śiṣyeṣu)</em>, [как] наипочтеннейший <em>(bhaṭṭaśrī)</em> Каллата <em>(kallaṭa)</em> и другие <em>(ādyeṣu)</em>, и <em>(ca)</em> собрал их <em>(etāni... saṅgṛhītavān)</em> в виде Spandakārikā-s <em>(spandakārikābhiḥ)</em>. Афоризмы <em>(sūtrāṇi)</em>, касающиеся Изначальной Вибрации <em>(spanda)</em> --т.е. Spandakārikā-s, или Spandasūtra-s--, полученные <em>(prāptāni)</em> из этой <em>(tad)</em> непрерывной ученической преемственности <em>(panorama)</em>, были полностью <em>(samyak)</em> удостоверены <em>(nirṇītāni)</em> нами <em>(asmābhiḥ)</em> в Spandanirṇaya <em>(spandanirṇaye)</em>. А сейчас <em>(tu)</em>, Śivasūtra-s <em>(śivasūtrāṇi)</em> проясняются <em>(nirṇīyante)</em>.</p><p>В них --т.е. в Śivasūtra-s-- <em>(tatra)</em>, в первую очередь <em>(prathamam)</em> разъясняется <em>(ādiśati)</em>, в полной противоположности <em>(prātipakṣyeṇa)</em> для тех, кто следует учению <em>(vādi)</em> о разнице <em>(bheda)</em> между человеком <em>(nara)</em> и Господом <em>(īśvara)</em>, что &quot;Шива <em>(śivaḥ)</em> один <em>(eva)</em>, (и) в высшем смысле <em>(paramārthatas)</em> [слова], Сознание <em>(caitanya)</em> [является] Высшим Я <em>(ātmā)</em> вселенной <em>(viśvasya... iti)</em>&quot;</p></div>',3);r.render=function(e,t,r,s,n,d){return a(),m("div",null,[i])};export default r;export{t as __pageData};
